float dist(Point p1, Point p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float d = p1.coord[i] - p2.coord[i];
    result += d * d;
  }
  return result;
}

float pspeedy(Points *points, float z, long *kcenter) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  cnt_speedy++;

#ifdef PRINTINFO
  fprintf(stderr, "Speedy: facility cost %lf\n", z);
#endif

#pragma omp parallel for schedule(static)
  for (long k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;

  for (long i = 1; i < points->num; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
#pragma omp parallel for schedule(static)
      for (long k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        float newcost = distance * points->p[k].weight;
        if (newcost < points->p[k].cost) {
          points->p[k].cost = newcost;
          points->p[k].assign = i;
        }
      }
    }
  }

  float totalcost = z * (*kcenter);
  for (long k = 0; k < points->num; k++) {
    totalcost += points->p[k].cost;
  }

#ifdef PRINTINFO
  fprintf(stderr, "Speedy opened %ld facilities for total cost %lf\n", *kcenter, totalcost);
  fprintf(stderr, "Distance Cost %lf\n", totalcost - z * (*kcenter));
#endif

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return totalcost;
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax,
            bool *is_center_arr, int *center_table_arr, char *switch_membership_arr,
            double *serial_t, double *cpu_gpu_memcpy_t, double *memcpy_back_t,
            double *gpu_malloc_t, double *kernel_t) {
#ifdef PROFILE_TMP
  double t_gain_start = gettime();
#endif
  (void)cpu_gpu_memcpy_t;
  (void)memcpy_back_t;
  (void)gpu_malloc_t;

  float gl_cost = 0.0f;
  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;

#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      center_table_arr[i] = count++;
    }
  }
#ifdef PROFILE_TMP
  double t2 = gettime();
  *serial_t += t2 - t1;
#endif

  ensure_pgain_buffers(num, kmax);

#ifdef PROFILE_TMP
  double t3 = gettime();
#endif
  memset(switch_membership_arr, 0, num * sizeof(char));
  memset(work_mem_h, 0, (size_t)(K + 1) * (size_t)num * sizeof(float));

  Point px = points->p[x];
#pragma omp parallel for schedule(static)
  for (int thread_id = 0; thread_id < num; thread_id++) {
    float x_cost = 0.0f;
    for (int i = 0; i < dim; i++) {
      float diff = points->p[thread_id].coord[i] - px.coord[i];
      x_cost += diff * diff;
    }
    x_cost *= points->p[thread_id].weight;

    float current_cost = points->p[thread_id].cost;
    int base = thread_id * (K + 1);

    if (x_cost < current_cost) {
      switch_membership_arr[thread_id] = '1';
      work_mem_h[base + K] = x_cost - current_cost;
    } else {
      long assign = points->p[thread_id].assign;
      int addr = base + center_table_arr[assign];
      work_mem_h[addr] += current_cost - x_cost;
    }
  }
#ifdef PROFILE_TMP
  double t4 = gettime();
  *kernel_t += t4 - t3;
#endif

#ifdef PROFILE_TMP
  double t5 = gettime();
#endif
  int numclose = 0;
  gl_cost = z;

  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      float low = z;
      int cidx = center_table_arr[i];
      for (int j = 0; j < num; j++) {
        low += work_mem_h[j * (K + 1) + cidx];
      }
      gl_lower[cidx] = low;

      if (low > 0) {
        numclose++;
        work_mem_h[i * (K + 1) + K] -= low;
      }
    }
    gl_cost += work_mem_h[i * (K + 1) + K];
  }

  if (gl_cost < 0) {
    for (int i = 0; i < num; i++) {
      bool close_center = gl_lower[center_table_arr[points->p[i].assign]] > 0;
      if ((switch_membership_arr[i] == '1') || close_center) {
        points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center_arr[i] && gl_lower[center_table_arr[i]] > 0) {
        is_center_arr[i] = false;
      }
    }

    is_center_arr[x] = true;
    *numcenters = *numcenters + 1 - numclose;
  } else {
    gl_cost = 0;
  }
#ifdef PROFILE_TMP
  double t6 = gettime();
  *serial_t += t6 - t5;
  time_gain += t6 - t_gain_start;
#endif

  return -gl_cost;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter, float e) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  long i;
  long x;
  float change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0f;

    intshuffle(feasible, numfeasible);

    for (i = 0; i < iter; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
                      &serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel);
    }

    cost -= change;
#ifdef PRINTINFO
    fprintf(stderr, "%ld centers, cost %lf, total distance %lf\n", *k, cost, cost - z * (*k));
#endif
  }

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_FL += t2 - t1;
#endif
  return cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc(numfeasible * sizeof(int));

  float *accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = (int)k1; i < k2; i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight = (float *)malloc(sizeof(float) * points->num);
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = (int)k1; i < k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = (int)points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }
  free(accumweight);

#ifdef PROFILE_TMP
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long *kfinal) {
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  long k = 0;
  int *feasible = NULL;
  int numfeasible = 0;

  hiz = loz = 0.0f;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

#ifdef PRINTINFO
  printf("Starting Kmedian procedure\n");
  printf("%li points in %li dimensions\n", numberOfPoints, ptDimension);
#endif

  for (long kk = 0; kk < points->num; kk++) {
    hiz += dist(points->p[kk], points->p[0], (int)ptDimension) * points->p[kk].weight;
  }

  loz = 0.0f;
  z = (hiz + loz) / 2.0f;

  if (points->num <= kmax) {
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    *kfinal = points->num;
    return 0.0f;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k);

#ifdef PRINTINFO
  printf("Finished first call to speedy, cost=%lf, k=%ld\n", cost, k);
#endif

  i = 0;
  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k);
    i++;
  }

#ifdef PRINTINFO
  printf("second call to speedy, cost=%lf, k=%ld\n", cost, k);
#endif

  while (k < kmin) {
#ifdef PRINTINFO
    printf("%lf %lf\n", loz, hiz);
    printf("Speedy indicates we should try lower z\n");
#endif
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, (int)kmin);
  for (int j = 0; j < points->num; j++) {
    is_center[points->p[j].assign] = true;
  }

  while (1) {
#ifdef PRINTINFO
    printf("loz = %lf, hiz = %lf\n", loz, hiz);
    printf("Running Local Search...\n");
#endif

    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
               z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.1f);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
#ifdef PRINTINFO
      printf("Trying a more accurate local search...\n");
#endif
      cost = pFL(points, feasible, numfeasible,
                 z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.001f);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }

    if (cost == lastcost) {
      break;
    }
  }

  free(feasible);
  *kfinal = k;
  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0f - relweight;
        points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points *centers, long *centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;
  free(is_a_median);
}

void localSearch(Points *points, long kmin, long kmax, long *kfinal) {
#ifdef PROFILE_TMP
  double t1 = gettime();
#endif
  pkmedian(points, kmin, kmax, kfinal);
#ifdef PROFILE_TMP
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

